import { Component, OnInit } from "@angular/core";
import { SearchResult } from "src/app/views/Models/References/SearchResult";
import { ReferencesService } from "src/app/core/services/references.service";
import { ITransType } from "src/app/views/Models/References/TransactionsType";
import { FormBuilder, FormGroup, Validators } from "@angular/forms";
import { StaticRef } from "src/app/views/Models/References/StaticRef";
import { Bank } from "src/app/views/Models/Settings/BranchReference";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { ClientTransactionsService } from "src/app/core/services/client-transactions.service";
import { ClientTrasnaction } from "src/app/views/Models/ClientTransactions/ClientTransaction";
import { formatNumber } from "@angular/common";
import { format } from "date-fns";
import { AlertService } from "src/app/core/services/alert.service";
import {
  bankNameValidator,
  dateTypeStringValidator,
  transactionAmountValidator,
  transactionTypeValidator,
} from "src/app/core/validators/custom-validators";
import { InputMaskingService } from "src/app/core/services/input-masking.service";

interface SearchTypeObject {
  pageAction: number;
}

interface CheckPageTypes {
  isAddingTransaction: boolean;
  isEditingTransaction: boolean;
  isDeletingTransaction: boolean;
}

@Component({
  selector: "app-client-financial-transaction",
  templateUrl: "./client-financial-transaction.page.html",
  styleUrls: ["./client-financial-transaction.page.scss"],
})
export class ClientFinancialTransactionPage implements OnInit {
  searchTypeObject: SearchTypeObject = { pageAction: null };
  pageTypeAccessRights: any[];

  showLoader: boolean = false;
  isSearching: boolean = true;
  checkInputsValidation: boolean = false;
  openClientTransactionForm: boolean = false;
  checkPageTypes: CheckPageTypes = {
    isAddingTransaction: false,
    isEditingTransaction: false,
    isDeletingTransaction: false,
  };

  clientTransTypes: ITransType[] = [];
  bankTypes: StaticRef[] = [];
  banks: Bank[] = [];
  transactions: ClientTrasnaction[];
  clientTransaction: ClientTrasnaction;

  clientTransactionPageType: any[] = [
    {
      pageTypeDesc: "إدخال حركات ماليه للعملاء ",
      pageCode: 5623,
      pageAction: 1,
      hasPermission: false,
    },
    {
      pageTypeDesc: "تعديل حركات ماليه للعملاء ",
      pageCode: 5624,
      pageAction: 3,
      hasPermission: false,
    },
    {
      pageTypeDesc: "حذف حركات ماليه للعملاء ",
      pageCode: 5625,
      pageAction: 3,
      hasPermission: false,
    },
  ];
  selectedPageSegment: any;

  clientForm: FormGroup = this.formBuilder.group({
    clientName: [null],
    clientCode: [null],
  });
  clientTransactionForm: FormGroup = this.formBuilder.group({
    clientKey: [null],
    transCode: [null],
    transactionType: [
      null,
      transactionTypeValidator({
        required: true,
      }),
    ],
    transAmount: [
      null,
      transactionAmountValidator({
        required: true,
        valueGreaterThanZero: true,
      }),
    ],
    transActionDate: [
      null,
      dateTypeStringValidator({
        required: true,
      }),
    ],
    transVouch: [null],
    bankType: ["1"],
    bankKey: [null, [bankNameValidator({ required: true })]],
    uuc: [null],
  });

  constructor(
    private referencesService: ReferencesService,
    private formBuilder: FormBuilder,
    private authService: MohassilAuthService,
    private clientTransactionsService: ClientTransactionsService,
    private alertService: AlertService,
    public inputMaskingService: InputMaskingService
  ) {}

  async ngOnInit() {
    this.pageTypeAccessRights = await this.authService.getAccessRights();
    // Filter the clientTransactionPageType array according to access rights
    // const filteredClientTransactionPageTypes =
    //   this.clientTransactionPageType.filter((page) => {
    //     return this.windowCodesToCheck.some(
    //       (x) => x === page.pageCode.toString() && this.checkWindowCodeExists(x)
    //     );
    //   });

    const filteredClientTransactionPageTypes =
      this.clientTransactionPageType.map((page) => {
        const hasPermission = this.checkWindowCodeExists(
          page.pageCode.toString()
        );
        return { ...page, hasPermission };
      });
    this.clientTransactionPageType = filteredClientTransactionPageTypes.filter(
      (x) => x.hasPermission === true
    );

    this.selectedPageSegment = this.clientTransactionPageType.find(() => true);
    this.setSelectedTransactionSegment(
      this.selectedPageSegment.pageCode.toString()
    );
    this.searchTypeObject.pageAction = this.selectedPageSegment?.pageAction;
    console.log(this.clientTransactionPageType);
  }
  changePageType(event) {
    this.isSearching = true;
    this.selectedPageSegment = this.clientTransactionPageType.find(
      (x) => x.pageCode.toString() === event.detail.value.toString()
    );
    this.setSelectedTransactionSegment(event.detail.value.toString());
    this.searchTypeObject.pageAction = this.selectedPageSegment.pageAction;
  }
  async clientSelected(event: SearchResult) {
    this.showLoader = true;
    this.isSearching = false;
    this.transactions =
      await this.clientTransactionsService.getClientTransactions(
        event.client_key.toString()
      );
    this.clientForm.patchValue({
      clientName: event.client_name,
      clientCode: event.org_branch_code + "/" + event.client_code,
    });
    this.clientTransactionForm.patchValue({
      clientKey: event.client_key,
    });
    this.clientTransTypes = await this.referencesService.getClientTransTypes();
    this.bankTypes = await this.referencesService.getBankType();
    this.getBanks();
    switch (this.selectedPageSegment.pageCode.toString()) {
      case "5623": {
        this.checkPageTypes.isAddingTransaction = true;
        this.checkPageTypes.isEditingTransaction = false;
        this.checkPageTypes.isDeletingTransaction = false;
        this.openClientTransactionForm = true;
        break;
      }
      case "5624": {
        this.checkPageTypes.isAddingTransaction = false;
        this.checkPageTypes.isEditingTransaction = true;
        this.checkPageTypes.isDeletingTransaction = false;
        this.openClientTransactionForm = false;
        break;
      }
      case "5625": {
        this.checkPageTypes.isAddingTransaction = false;
        this.checkPageTypes.isEditingTransaction = false;
        this.checkPageTypes.isDeletingTransaction = true;
        this.openClientTransactionForm = false;
        break;
      }
    }
    if (this.selectedPageSegment.pageCode.toString() === "5623")
      this.openClientTransactionForm = true;
    this.showLoader = false;
  }
  async getBanks() {
    this.clientTransactionForm.patchValue({
      bankKey: null,
    });
    this.banks = await this.referencesService.getBanksByBankType(
      Number(this.clientTransactionForm.value.bankType)
    );
  }
  backBtn() {
    //open search component
    if (
      !this.isSearching &&
      !this.openClientTransactionForm &&
      !this.checkPageTypes.isAddingTransaction
    ) {
      this.isSearching = true;
    }
    // open client transaction grid
    if (!this.isSearching && this.openClientTransactionForm) {
      this.isSearching = false;
      this.openClientTransactionForm = false;
    }
    // if adding transaction back to search component direct
    if (this.checkPageTypes.isAddingTransaction) {
      this.isSearching = true;
    }
  }
  async openEditForm(transaction: ClientTrasnaction) {
    this.openClientTransactionForm = true;
    this.clientTransaction =
      await this.clientTransactionsService.getClientTransactionByTransCode(
        Number(transaction.trans_code)
      );
    this.clientTransactionForm.patchValue({
      transactionType: this.clientTransaction.type_key,
      transCode: Number(transaction.trans_code),
      transAmount: formatNumber(
        Number(this.clientTransaction.trans_amount),
        "en-US",
        "1.0-2"
      ),
      transActionDate: format(
        new Date(this.clientTransaction.trans_act_date),
        "yyyy-MM-dd"
      ),
      transVouch: this.clientTransaction.trans_vouch,
      bankType: this.clientTransaction.bank_type.toString(),
      bankKey: this.clientTransaction.cur_bank_key.toString(),
      uuc: this.clientTransaction.uuc.toString(),
    });
  }
  async deleteClientTransaction(transaction: ClientTrasnaction) {
    if (!(await this.alertService.SaveAlert())) return;
    try {
      this.showLoader = true;
      await this.clientTransactionsService.deleteClientTransaction(
        Number(transaction.trans_code),
        transaction.uuc.toString()
      );
      this.alertService.showAlertConfirm("لقد تم حذف الحركة ", true);
    } catch (error) {
      this.alertService.showAlertError(error.error, false);
      throw error;
    } finally {
      this.showLoader = false;
    }
  }
  async insertClientTransaction() {
    if (!this.clientTransactionForm.valid)
      return (this.checkInputsValidation = true);
    if (!(await this.alertService.SaveAlert())) return;
    try {
      this.showLoader = true;
      await this.clientTransactionsService.insertClientTransaction(
        this.clientTransactionForm.value
      );
      this.alertService.showAlertConfirm("لقد تم الحفظ بنجاح", true);
    } catch (error) {
      this.alertService.showAlertError(error.error, false);
      throw error;
    } finally {
      this.showLoader = false;
    }
  }
  async editClientTransaction() {
    if (!this.clientTransactionForm.valid)
      return (this.checkInputsValidation = true);
    if (!(await this.alertService.SaveAlert())) return;
    try {
      this.showLoader = true;
      await this.clientTransactionsService.editClientTransaction(
        this.clientTransactionForm.value
      );
      this.alertService.showAlertConfirm("لقد تم الحفظ بنجاح", true);
    } catch (error) {
      this.alertService.showAlertError(error.error, false);
      throw error;
    } finally {
      this.showLoader = false;
    }
  }
  checkWindowCodeExists = (WindowCode: string): boolean => {
    return this.pageTypeAccessRights?.some((x) => x.window_code === WindowCode);
  };
  setSelectedTransactionSegment(windowCode: string) {
    this.selectedPageSegment = this.clientTransactionPageType.find(
      (x) => x.pageCode.toString() === windowCode
    );
  }
}
